#include <stdio.h>

int main() {
  int arr[] = {10, 20, 30, 40, 50};
  int *ptr = arr;
  printf("%d ", *ptr);
  ptr++;
  printf("%d ", *ptr);
  ptr += 2;
  printf("%d\n", *ptr);
  ptr--;
  printf("%d\n", *ptr);
  int *end = &arr[4];
  printf("Elements between: %td\n", end - arr);
  return 0;
}
